package com.flowledger.supplier.service; import com.flowledger.common.service.OrganizationScopedService; import com.flowledger.supplier.dto.SupplierDtos.*; import com.flowledger.supplier.entity.Supplier; import com.flowledger.supplier.mapper.SupplierMapper; import com.flowledger.supplier.repository.SupplierRepository; import org.springframework.data.domain.*; import org.springframework.data.jpa.domain.Specification; import org.springframework.http.HttpStatus; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import org.springframework.web.server.ResponseStatusException; import java.math.*; import java.util.*; @Service @Transactional public class SupplierService extends OrganizationScopedService {private final SupplierRepository repo;private final SupplierMapper mapper;public SupplierService(SupplierRepository r,SupplierMapper m){repo=r;mapper=m;}public Response create(Create d){if(repo.existsByOrganizationIdAndSupplierCode(orgId(),d.supplierCode()))throw new ResponseStatusException(HttpStatus.CONFLICT,"Supplier code already exists");Supplier e=mapper.toEntity(d);e.setOrganizationId(orgId());return mapper.toResponse(repo.save(e));}@Transactional(readOnly=true)public Response get(UUID id){return mapper.toResponse(load(id));}public Response update(UUID id,Update d){Supplier e=load(id);mapper.update(d,e);return mapper.toResponse(repo.save(e));}public void archive(UUID id){Supplier e=load(id);e.setArchived(true);repo.save(e);}@Transactional(readOnly=true)public Page<Response> search(Search f,Pageable p){Specification<Supplier>s=(r,q,b)->b.equal(r.get("organizationId"),orgId());if(f.archived()!=null)s=s.and((r,q,b)->b.equal(r.get("archived"),f.archived()));if(f.search()!=null&&!f.search().isBlank()){String x="%"+f.search().toLowerCase()+"%";s=s.and((r,q,b)->b.or(b.like(b.lower(r.get("supplierName")),x),b.like(b.lower(r.get("supplierCode")),x)));}return repo.findAll(s,p).map(mapper::toResponse);}@Transactional(readOnly=true)public Statement statement(UUID id){Supplier e=load(id);return new Statement(e.getOpeningBalance(),BigDecimal.ZERO,e.getOpeningBalance());}@Transactional(readOnly=true)public BigDecimal outstanding(UUID id){return statement(id).balance();}private Supplier load(UUID id){return required(repo.findByIdAndOrganizationId(id,orgId()),"Supplier");}}